/* CBMC models for editorReadKey's external callees: read() and exit().
 *
 * Without bodies CBMC treats read() as a nondeterministic no-op that does not
 * even write the byte it "reads", so the entire key-decoding logic becomes
 * unconstrained and a return-value contract can pin nothing.  These models make
 * the terminal input a *scripted* sequence held in the rk_* globals:
 *
 *   rk_ret[i]  is the return value of the i-th read():  -1 (error),
 *              0 (timeout / no byte), or 1 (one byte delivered).
 *   rk_byte[i] is the byte delivered by the i-th read() when rk_ret[i] > 0.
 *
 * With this, editorReadKey's result is a deterministic function of the rk_*
 * globals, which its contract reproduces exactly -- so any mutant that decodes
 * the escape sequence differently returns a value that diverges from the
 * contract and is killed.  exit() never returns (it ends the trace), matching
 * the real semantics.
 *
 * The stub is linked into a verification run only when read()/exit() appear in
 * the target's external-callee list, i.e. only for editorReadKey. */

#include <stddef.h>

typedef long ssize_t;

/* Scripted terminal input.  Sized well past the at-most-four reads a single
 * returning call performs, with an in-model bound check so a mutant that loops
 * and over-reads can never index out of range here. */
#define RK_MAX 32
int  rk_idx;
int  rk_ret[RK_MAX];
char rk_byte[RK_MAX];

/* FUNCTION: read */
ssize_t read(int fd, void *buf, size_t count)
{
    (void)fd;
    (void)count;
    int i = rk_idx;
    if (i < 0 || i >= RK_MAX) return 0;
    rk_idx = i + 1;
    if (rk_ret[i] > 0) ((char *)buf)[0] = rk_byte[i];
    return (ssize_t)rk_ret[i];
}

/* FUNCTION: exit */
void exit(int status)
{
    (void)status;
    __CPROVER_assume(0); /* exit() never returns: prune the trace here. */
}

